public void testToClass_objectWithNullAtStart() {
    assertTrue(Arrays.equals(new Class[] { null, String.class, Integer.class },
            ClassUtils.toClass(new Object[] { null, "Test", 1 })));
}

public void testToClass_objectWithAllNulls() {
    assertTrue(Arrays.equals(new Class[] { null, null, null },
            ClassUtils.toClass(new Object[] { null, null, null })));
}

public void testToClass_objectWithMultipleNulls() {
    assertTrue(Arrays.equals(new Class[] { null, Integer.class, null, String.class, null },
            ClassUtils.toClass(new Object[] { null, 42, null, "Test", null })));
}
